  ('police-b20a8cf8-moex-00316', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '前年報載南部某醫院毒物檢驗室負責南部地院毒品檢驗案，疑似將多件 3 級毒品誤判為 2 級毒 品，而造成多人可能冤獄賠償。其中原因為此二者毒品為同分異構物而造成檢驗誤判，請問下列 敘述何者正確？', '["把3,4-亞甲基雙氧苯基乙基胺丁酮誤判為3,4-亞甲基雙氧苯基甲胺戊酮", "把3,4-亞甲基雙氧苯基二甲胺丁酮誤判為3,4-亞甲基雙氧苯基乙基胺丁酮", "把3,4-亞甲基雙氧苯基甲胺戊酮誤判為3,4-亞甲基雙氧苯基乙基胺丁酮", "把3,4-亞甲基雙氧苯基甲胺戊酮誤判為3,4-亞甲基雙氧苯基二甲胺丁酮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
